(()=>{document.addEventListener("DOMContentLoaded",()=>{let m=document.querySelector("[data-post-content]"),t=document.querySelector("[data-post-toc-list]");if(m&&t){let d=Array.from(m.querySelectorAll("h2, h3"));if(d.length>0){for(;t.firstChild;)t.removeChild(t.firstChild);let l=null;d.forEach((e,s)=>{let a=e.textContent.trim();if(!a)return;let c=`toc-section-${Math.random().toString(36).substr(2,5)}-${s}`;e.id=c;let o=e.tagName.toLowerCase(),n=document.createElement("li");n.className="list-none p-0 m-0";let i=document.createElement("a");i.href=`#${e.id}`,i.className="no-underline text-fg-subtle/70 hover:text-fg-link transition-colors duration-200 block";let u=document.createElement("span");u.textContent=a;let p=o==="h2"?"text-sm":"text-xs";if(u.className=`${p} data-current:text-fg-default transition-colors duration-200 data-current:font-medium leading-none block py-1`,i.appendChild(u),n.appendChild(i),o==="h2")t.appendChild(n),l=n;else if(o==="h3")if(l){let r=l.querySelector("ul");r||(r=document.createElement("ul"),r.className="border-l border-stroke-default/50 pl-2 my-2",l.appendChild(r)),r.appendChild(n)}else t.appendChild(n)});let f=new IntersectionObserver(e=>{e.forEach(s=>{if(s.isIntersecting){let a=s.target.getAttribute("id"),c=t.querySelector(`a[href="#${a}"]`);if(c){let o=c.querySelector("span");t.querySelectorAll("span").forEach(n=>n.removeAttribute("data-current")),o&&o.setAttribute("data-current","")}}})},{root:null,rootMargin:"-5% 0px -80% 0px",threshold:0});d.forEach(e=>f.observe(e))}}});})();
